/* mwrap object-pointer type: forward-declared handle (defined in src/capi.cpp).
 * capi.h only typedefs the pointer (simdrng_t), so name the struct here. */
typedef struct simdrng_state simdrng_state;

static simdrng_state *sr_create_w(int kind, double seed_hi, double seed_lo)
{
    /* Rejoin the 64-bit seed from two exact-as-double 32-bit halves. */
    uint64_t seed = ((uint64_t)(uint32_t)seed_hi << 32) | (uint32_t)seed_lo;
    simdrng_t g = simdrng_create((simdrng_kind)kind, seed);
    if (!g)
        mexErrMsgIdAndTxt("simdrng:create", "%s", simdrng_last_error());
    return (simdrng_state *)g;
}

static void sr_free_w(simdrng_state *h) { simdrng_free((simdrng_t)h); }

static int sr_get_kind_w(simdrng_state *h) { return (int)simdrng_get_kind((simdrng_t)h); }

static void sr_fill_double_w(simdrng_state *h, double *y, int64_t n)
{
    simdrng_fill_double((simdrng_t)h, y, (size_t)n);
}

/* Raw uint64 draws as a genuine mxUINT64 column vector (lossless). */
static mxArray *sr_fill_u64_w(simdrng_state *h, int64_t n)
{
    mxArray *out = mxCreateNumericMatrix((mwSize)n, 1, mxUINT64_CLASS, mxREAL);
#if defined(MX_HAS_INTERLEAVED_COMPLEX) && MX_HAS_INTERLEAVED_COMPLEX
    uint64_t *y = mxGetUint64s(out);
#else
    uint64_t *y = (uint64_t *)mxGetData(out);
#endif
    simdrng_fill_u64((simdrng_t)h, y, (size_t)n);
    return out;
}
